def write(path: Path, text: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text.strip() + "\n", encoding="utf-8", newline="\n")


def md_table(headers: list[str], rows: list[tuple[str, ...]]) -> str:
    out = ["| " + " | ".join(headers) + " |", "| " + " | ".join(["---"] * len(headers)) + " |"]
    out.extend("| " + " | ".join(row) + " |" for row in rows)
    return "\n".join(out)


def manifest(name: str, target: Path, title: str, body: str) -> Path:
    chunk = SECTIONS / f"{name}.body.md"
    write(chunk, body)
    data = {
        "target_path": str(target.resolve()),
        "sections": [{"level": 2, "heading": title, "content_file": os.path.relpath(chunk, MANIFESTS)}],
    }
    path = MANIFESTS / f"{name}.manifest.json"
    write(path, json.dumps(data, ensure_ascii=False, indent=2))
    return path


def manifest_with_preamble(name: str, target: Path, preamble: str, sections: list[tuple[int, str, str]]) -> Path:
    preamble_path = SECTIONS / f"{name}.preamble.md"
    write(preamble_path, preamble)
    rendered = []
    for idx, (level, heading, body) in enumerate(sections, start=1):
        chunk = SECTIONS / f"{name}.{idx:02d}.md"
        write(chunk, body)
        rendered.append({"level": level, "heading": heading, "content_file": os.path.relpath(chunk, MANIFESTS)})
    data = {
        "target_path": str(target.resolve()),
        "preamble_file": os.path.relpath(preamble_path, MANIFESTS),
        "sections": rendered,
    }
    path = MANIFESTS / f"{name}.manifest.json"
    write(path, json.dumps(data, ensure_ascii=False, indent=2))
    return path


def tc_markdown() -> str:
    blocks = []
    for tc_id, package, tc_type, priority, trace, title, pre, data, steps, expected, post in TCS:
        step_text = "\n".join(f"{idx}. {step}" for idx, step in enumerate(steps, start=1))
        blocks.append(
            f"""### {tc_id}

**Название:** {title}
**Тип:** {tc_type}
**Приоритет:** {priority}
**package_id:** {package}
**Трассировка:** {trace}

#### Предусловия

{pre}

#### Тестовые данные

{data}

#### Шаги

{step_text}

#### Итоговый ожидаемый результат

{expected}

#### Постусловия

{post}
"""
        )
    return "\n".join(blocks)


